export type AlignedDiffVerificationLayer = "unit" | "functional" | "e2e";

export type AlignedDiffSemanticLayer =
  | "fixture"
  | "model"
  | "mapping"
  | "pane"
  | "connector"
  | "profile"
  | "surface";

export interface AlignedDiffTraceabilityEntry {
  issueId: `ASD-${string}`;
  title: string;
  semanticLayers: readonly AlignedDiffSemanticLayer[];
  verification: Readonly<Record<AlignedDiffVerificationLayer, readonly string[]>>;
}

const E2E_VISUAL = "e2e/diff-a11y-visual.spec.ts";
const E2E_PREVIEW = "e2e/diff-file-preview.spec.ts";
const E2E_REVIEW = "e2e/file-review.spec.ts";
const E2E_GIT = "e2e/git-local-changes.spec.ts";
const E2E_PERFORMANCE = "e2e/diff-performance.spec.ts";
const E2E_LAZY = "e2e/diff-lazy-loading.spec.ts";

function entry(
  issueId: AlignedDiffTraceabilityEntry["issueId"],
  title: string,
  semanticLayers: readonly AlignedDiffSemanticLayer[],
  unit: readonly string[],
  functional: readonly string[],
  e2e: readonly string[],
): AlignedDiffTraceabilityEntry {
  return { issueId, title, semanticLayers, verification: { unit, functional, e2e } };
}

